import React from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

const getWeatherEmoji = (condition: string): string => {
  const normalizedCondition = condition.toLowerCase();
  if (normalizedCondition.includes('sunny') || normalizedCondition.includes('clear')) return '☀️';
  if (normalizedCondition.includes('cloudy') || normalizedCondition.includes('cloud')) return '☁️';
  if (normalizedCondition.includes('rainy') || normalizedCondition.includes('rain')) return '🌧️';
  if (normalizedCondition.includes('snowy') || normalizedCondition.includes('snow')) return '❄️';
  if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return '⛈️';
  if (normalizedCondition.includes('windy') || normalizedCondition.includes('wind')) return '🌪️';
  if (normalizedCondition.includes('foggy') || normalizedCondition.includes('fog')) return '🌫️';
  return '🌡️';
};

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  return (
    <Card
      padding="24"
      shadow="md"
      border={true}
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        {/* Header with City Name */}
        <Text
          variant="h2"
          color="var(--ggui-color-onSurface, #18181b)"
          weight="bold"
        >
          {city}
        </Text>

        {/* Current Temperature and Condition */}
        <Stack direction="horizontal" gap={16} align="center">
          <div
            style={{
              fontSize: '72px',
              lineHeight: '1',
            }}
          >
            {getWeatherEmoji(condition)}
          </div>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="h1"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="bold"
            >
              {temperature}°{unit}
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="medium"
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-outline, #d4d4d8)',
            margin: 'var(--ggui-spacing-2, 8px) 0',
          }}
        />

        {/* Humidity and Wind Speed */}
        <Row gap={24} justify="start">
          <Stack direction="vertical" gap={4}>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="medium"
            >
              Humidity
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="semibold"
            >
              {humidity}%
            </Text>
          </Stack>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="medium"
            >
              Wind Speed
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="semibold"
            >
              {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
            </Text>
          </Stack>
        </Row>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-outline, #d4d4d8)',
            margin: 'var(--ggui-spacing-2, 8px) 0',
          }}
        />

        {/* 5-Day Forecast Strip */}
        <Stack direction="vertical" gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>
          <Row
            gap={8}
            justify="start"
            wrap={true}
            style={{
              overflowX: 'auto',
            }}
          >
            {forecast.map((day, index) => (
              <Box
                key={index}
                padding="12"
                borderRadius="8"
                style={{
                  backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  minWidth: '110px',
                  textAlign: 'center',
                  flexShrink: 0,
                }}
              >
                <Stack direction="vertical" gap={8} align="center">
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurface, #18181b)"
                    weight="semibold"
                  >
                    {day.day}
                  </Text>
                  <div style={{ fontSize: '32px' }}>
                    {day.icon}
                  </div>
                  <Stack direction="horizontal" gap={4} align="center" justify="center">
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurface, #18181b)"
                      weight="semibold"
                    >
                      {day.high}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
